// AICP Ingress Parser — n8n Code Node
// Parses raw AICP/1.0 text protocol packets into structured JSON

const rawBody = $input.first().json.body?.message || $input.first().json.message || $input.first().json.body;
const raw = typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody);

// Normalize CRLF
const text = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
const lines = text.split('\n');

// --- Phase 1: Split headers from payload ---
const headers = {};
const payloadLines = [];
let inPayload = false;

for (const line of lines) {
  const trimmed = line.trim();

  if (trimmed === '---PAYLOAD---') {
    inPayload = true;
    continue;
  }
  if (trimmed === '---END---') {
    inPayload = false;
    continue;
  }

  if (inPayload) {
    payloadLines.push(line);
    continue;
  }

  // Parse key: value pairs (supports $KEY and plain KEY with spaces/hyphens)
  const kvMatch = trimmed.match(/^(\$?[A-Za-z][A-Za-z0-9_ .\-]*?)\s*:\s*(.*)$/);
  if (kvMatch) {
    const key = kvMatch[1].trim();
    const value = kvMatch[2].trim();
    headers[key] = value;
  }
}

const payloadText = payloadLines.join('\n').replace(/^\n+|\n+$/g, '');

// --- Phase 2: Normalize canonical fields ---
const toRaw = headers['$TO'] || '';
const targets = toRaw.split(',').map(t => t.trim()).filter(Boolean);

const normalized = {
  proto:    headers['$PROTO'] || '',
  type:     headers['$TYPE'] || '',
  id:       headers['$ID'] || '',
  ref:      headers['$REF'] || null,
  seq:      headers['$SEQ'] ? parseInt(headers['$SEQ'], 10) : null,
  from:     headers['$FROM'] || '',
  to:       targets,
  time:     headers['$TIME'] || '',
  task:     headers['$TASK'] || '',
  status:   headers['$STATUS'] || '',
  priority: headers['$PRIORITY'] || null,
  role:     headers['$ROLE'] || null,
  intent:   headers['$INTENT'] || null
};

// --- Phase 3: Extract custom (non-$) headers ---
const custom = {};
for (const [key, value] of Object.entries(headers)) {
  if (!key.startsWith('$')) {
    custom[key] = value;
  }
}

// --- Phase 4: Determine route from $TO ---
let route = 'route_unknown';
const lower = targets.map(t => t.toLowerCase());

if (targets.length > 1) {
  route = 'route_multi';
} else if (lower.includes('pharos')) {
  route = 'route_pharos';
} else if (lower.includes('lodestar')) {
  route = 'route_lodestar';
} else if (lower.includes('don')) {
  route = 'route_don';
} else if (lower.includes('forge')) {
  route = 'route_forge';
} else if (lower.includes('spindrift')) {
  route = 'route_spindrift';
}

// --- Phase 5: Build routing namespace ---
const routing = {
  targets: targets,
  route: route,
  isMulti: targets.length > 1,
  handlerMode: targets.length > 1 ? 'multi' : 'single',
  registry: null
};

// --- Phase 6: Validate required fields ---
const validation = {
  valid: true,
  errors: []
};

if (!normalized.proto) {
  validation.valid = false;
  validation.errors.push('Missing $PROTO');
}
if (!normalized.id) {
  validation.valid = false;
  validation.errors.push('Missing $ID');
}
if (!normalized.type) {
  validation.valid = false;
  validation.errors.push('Missing $TYPE');
}
if (targets.length === 0) {
  validation.valid = false;
  validation.errors.push('Missing or empty $TO');
}

// --- Phase 7: Build acknowledgment ---
const ack = {
  id: normalized.id,
  route: routing.route,
  received: new Date().toISOString()
};

// --- Build journal filename (mirrors server.py convention) ---
let datePart = '';
try {
  datePart = normalized.time.substring(0, 10);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(datePart)) throw 'bad';
} catch(e) {
  datePart = new Date().toISOString().substring(0, 10);
}
const journalFile = `${datePart}-${normalized.id}-${normalized.type.toLowerCase()}-${normalized.from.toLowerCase().replace(/ /g, '-')}.md`;

const result = {
  headers,
  normalized,
  custom,
  payloadLines,
  payloadText,
  routing,
  validation,
  ack,
  journalFile
};

return [{ json: result }];

const item = $input.first().json;
item.routing.targetResolved = 'Pharos';
item.routing.handlerMode = 'single';
item.routing.handlerStatus = 'live';
item.deliveryReport = {
  target: 'Pharos',
  mode: 'notification',
  timestamp: new Date().toISOString()
};
item.webhookPayload = {
  event: 'new_message',
  messageId: item.normalized.id,
  from: item.normalized.from,
  type: item.normalized.type,
  task: item.normalized.task,
  project: item.custom.PROJECT || 'InterAI-Protocol',
  journalFile: item.journalFile,
  timestamp: new Date().toISOString()
};
return [{ json: item }];

const item = $input.first().json;
item.routing.targetResolved = 'Lodestar';
item.routing.handlerMode = 'single';
item.routing.handlerStatus = 'live';
item.deliveryReport = {
  target: 'Lodestar',
  mode: 'full_delivery',
  timestamp: new Date().toISOString()
};
item.webhookPayload = {
  event: 'message_delivery',
  messageId: item.normalized.id,
  from: item.normalized.from,
  to: item.normalized.to,
  type: item.normalized.type,
  task: item.normalized.task,
  status: item.normalized.status,
  project: item.custom.PROJECT || 'InterAI-Protocol',
  payloadText: item.payloadText,
  journalFile: item.journalFile,
  timestamp: new Date().toISOString()
};
return [{ json: item }];

const item = $input.first().json;
const targets = item.routing.targets || [];
const results = [];

// Agent delivery config — local agents get notification, remote get full delivery
const agentConfig = {
  'don':       { url: 'http://localhost:8080/agents/don/notify',       mode: 'notification' },
  'pharos':    { url: 'http://localhost:8080/agents/pharos/notify',    mode: 'notification' },
  'spindrift': { url: 'http://localhost:8080/agents/spindrift/notify', mode: 'notification' },
  'lodestar':  { url: 'http://localhost:8080/agents/lodestar/deliver', mode: 'full_delivery' },
  'forge':     { url: 'http://localhost:8080/agents/forge/deliver',    mode: 'full_delivery' }
};

for (const target of targets) {
  const key = target.toLowerCase();
  const config = agentConfig[key] || { url: null, mode: 'unknown' };

  const outItem = JSON.parse(JSON.stringify(item));
  outItem.routing.targetResolved = targets.join('+');
  outItem.routing.handlerMode = 'multi';
  outItem.routing.handlerStatus = 'live';
  outItem.deliveryReport = {
    target: target,
    mode: config.mode,
    timestamp: new Date().toISOString()
  };

  if (config.mode === 'full_delivery') {
    outItem.webhookPayload = {
      event: 'message_delivery',
      messageId: item.normalized.id,
      from: item.normalized.from,
      to: item.normalized.to,
      type: item.normalized.type,
      task: item.normalized.task,
      status: item.normalized.status,
      project: item.custom.PROJECT || 'InterAI-Protocol',
      payloadText: item.payloadText,
      journalFile: item.journalFile,
      timestamp: new Date().toISOString()
    };
  } else {
    outItem.webhookPayload = {
      event: 'new_message',
      messageId: item.normalized.id,
      from: item.normalized.from,
      type: item.normalized.type,
      task: item.normalized.task,
      project: item.custom.PROJECT || 'InterAI-Protocol',
      journalFile: item.journalFile,
      timestamp: new Date().toISOString()
    };
  }
  outItem.webhookUrl = config.url;
  results.push({ json: outItem });
}

return results;

