const item = $input.first().json;
item.routing.targetResolved = 'Unknown';
item.routing.handlerMode = 'unresolved';
item.routing.handlerStatus = 'error';
item.deliveryReport = {
  target: 'Unknown',
  mode: 'none',
  error: 'No matching agent found for routing target',
  timestamp: new Date().toISOString()
};
return [{ json: item }];
